import { Component, h, Prop, State, Watch, Event, EventEmitter } from '@stencil/core';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import {
  CustomKeysV2,
  IDisabledSelected,
  IMenuItemV2,
  IMenuItemV2Entry,
  IMenuItemV2CurrentState,
  MenuItemV2Map
} from '@src/mx-components/menu-item/mx-menu-item-v2/mx-menu-item-v2.model';
import itemUtils from '@src/utils/mx-utils/mx-menu-item.utils';

@Component({
  tag: 'mx-menu-item-v2',
  styleUrl: 'mx-menu-item-v2.css'
})
export class MxMenuItemV2 {
  /*--------------------------------------------------------------------------------------------------------properties*/
  /** Sets the item model object. */
  @Prop() readonly item: IMenuItemV2 = null;
  /** Sets the item model as a flattened map.
   *  Where key is items value and entry is a special object describing the item.
   *  Can be used instead of item object. */
  @Prop() readonly itemMap: MenuItemV2Map = null;
  /** If true fixes errors in the input object:
   * 1. Sets selected to the children if parent is selected.
   * 2. Sets selected/indeterminate for parent according to children state.
   * 3. Sets indeterminate to false if it was true and selected was true.
   * 4. Ignore 'indeterminate' if the item has no children. */
  @Prop() readonly fixInput: boolean = false;
  /** Sets the query to highlight. */
  @Prop() readonly query: string = '';
  /** Sets css class to highlight passed query if it is found in label. */
  @Prop() readonly queryCssClass: string = 'text-brand-less-prominent';
  /** Should the query be case-sensitive. */
  @Prop() readonly queryCaseSensitive: boolean = false;
  /** Sets custom keys. */
  @Prop() readonly customKeys: CustomKeysV2 = { key: '', value: '' };

  /*-----------------------------------------------------------------------------------------------------------watches*/
  @Watch('item')
  itemChange(newItem: IMenuItemV2): void {
    this.initItemMapState(newItem, this.itemMap);
  }
  @Watch('itemMap')
  itemMapChange(newItemMap: MenuItemV2Map): void {
    this.initItemMapState(this.item, newItemMap);
  }

  /*------------------------------------------------------------------------------------------------------------events*/
  /** Emitted when the user selects a menu item. Emits the menu item selected. */
  @Event() itemSelected: EventEmitter<IMenuItemV2CurrentState>;
  /** Emitted when the user clicks caret to open the menu item and display children. Emits the full state of the item.  */
  @Event() itemDisplayChildrenChanged: EventEmitter<IMenuItemV2CurrentState>;

  /*------------------------------------------------------------------------------------------------------------states*/
  /** Object that stores item info, with all its structure flattened and accessible by key,
   * which is now the value of the item. Also, it tracks all the item state. */
  @State() _itemMap: MenuItemV2Map = null;

  /*---------------------------------------------------------------------------------------component-lifecycle-methods*/
  componentWillLoad(): void {
    this.initItemMapState(this.item, this.itemMap);
  }

  /*------------------------------------------------------------------------------------------------------------render*/
  render(): HTMLLIElement | string {
    return this.renderItem(this._itemMap['root'], false);
  }

  /*----------------------------------------------------------------------------------------------------render-helpers*/
  private readonly renderLabelPart = (part, cssClass): HTMLLIElement | string => {
    return <span class={cssClass}>{part}</span>;
  };

  private renderItem(item: IMenuItemV2Entry, isChild = true): HTMLLIElement | string {
    const hasItem = !isNullOrUndefined(item);

    if (!hasItem) {
      return '';
    }

    const hasChildren: boolean = hasItem && item.children && item.children.length > 0;
    const hasCaret: boolean = !item.hideCaret && hasChildren;
    let label: string = item.label;
    if (itemUtils.hasCustomKeys(this.customKeys)) {
      label = item[this.customKeys.key];
    }
    const labelParts: string[] = this.composeLabelParts(label);

    return <li
      class={{
        'mx-menu-item-v2 pr-4': true,
        'mx-menu-item-v2__compact': item.compactCheckbox,
        'text-tertiary': item.disabled,
        'mx-menu-item-v2__checkbox-no-caret': !isChild && !hasCaret,
        'pl-4': !isChild && hasCaret,
        'pl-24': isChild && !hasCaret
      }}
      tabIndex={item.disabled ? -1 : 0}
      title={item.showTitle ? label : ''}
      role='menuitem'>
      <div class={{
        'mx-menu-item-v2__container items-center': true,
        'mx-menu-item-v2__container_compact': item.compactCheckbox
      }}>

        { /* caret block */ }

        {
          hasCaret && (
            <button
              class={{
                'kds-DismissalButton kind-prominent variant-minimal mr-4 mx-menu-item-v2__caret-button': true,
                'text-tertiary': item.disabled
              }}
              onClick={() => this.handleDisplayChange(item)}>
              <kds-icon-caret-right
                size='s'
                class={{
                  'mx-menu-item-v2__caret': true,
                  'mx-menu-item-v2__caret_rotate': item.displayChildren
                }}/>
            </button>)

        }

        { /* label block */}

        <kds-label class='w-full'>
          {
            item.showCheckbox && <kds-checkbox
              compact={item.compactCheckbox}
              disabled={item.disabled}
              indeterminate={item.indeterminate}
              checked={item.selected}
              onClick={(event: MouseEvent) => this.handleCheckboxClick(event, item)}/>
          }
          <div class='truncate'>
            {
              labelParts.length > 0 ?
                <span>
                  {
                    labelParts.map((part: string) => {
                      const cssClass = part.toLowerCase() === this.query.toLowerCase() ? this.queryCssClass : '';
                      return this.renderLabelPart(part, cssClass);
                    })
                  }
                </span> :
                label
            }
          </div>
          { hasChildren && item.showChildCount ? <span class='ml-4'>({item.children.length})</span> : '' }
          <div class='ml-4'><slot/></div>
          { item.important ? <kds-icon-error size='s' class='ml-4'/> : '' }
        </kds-label>
      </div>

      {
        hasChildren && (item.hideCaret || item.displayChildren) ?
          <ul class={{
            'mx-menu-item-v2__list': true,
            'pl-24': hasCaret
          }}>
            { item.children.map((id: string) => this.renderItem(this._itemMap[id])) }
          </ul>
          :
          ''
      }
    </li>;
  }

  /*---------------------------------------------------------------------------------------------------private-methods*/
  private initItemMapState(item: IMenuItemV2, itemMapProp: MenuItemV2Map): void {
    let itemMap: MenuItemV2Map = itemMapProp ||
      itemUtils.composeItemMap(item, this.customKeys, {}, {}, 'root');

    if (this.fixInput) {
      itemMap = itemUtils.validateAndFixInput(itemMap);
    }

    this._itemMap = itemMap;
  }

  private handleCheckboxClick(event: MouseEvent, item: IMenuItemV2Entry): void {
    event.preventDefault();
    event.stopPropagation();

    const id: string = item.parentId == null ? 'root' : item.id;
    let newSelected = !item.selected;
    // if we have disabled children down in the tree and this very item now is indeterminate
    // then new selected state should be 'true' if at least one of the disabled child is selected
    // or 'false' if none of disabled children are selected!
    const disabledAndSelected: IDisabledSelected = itemUtils.hasDisabledAndSelectedChildren(this._itemMap, id);
    if (item.indeterminate && disabledAndSelected.disabled) {
      newSelected = disabledAndSelected.disabled && disabledAndSelected.selected;
    }

    this._itemMap = itemUtils.updateSelectedItemInMap(id, newSelected, this._itemMap);

    if (item.disabled) {
      return;
    }

    const currentEntry: IMenuItemV2Entry = this._itemMap[id];
    this.itemSelected.emit({
      originalItem: item.originalItem,
      item: currentEntry.originalItem, //todo: check if it is needed
      currentSelectedState: {
        selected: newSelected,
        indeterminate: currentEntry.indeterminate,
        displayChildren: currentEntry.displayChildren
      },
      // 'fullStateItem' is an item object with all fields filled including all states
      fullStateItem: itemUtils.composeItemWithCurrentStateFromMap(this._itemMap, 'root'),
      // 'fixedStateMap' is needed for the list component to get the full state of the item
      fixedStateMap: this._itemMap
    });
  }

  private handleDisplayChange(item: IMenuItemV2Entry): void {
    const updatedItem: IMenuItemV2Entry = { ...item, displayChildren: !item.displayChildren };
    if (this._itemMap.hasOwnProperty(item.parentId)) {
      const parent: IMenuItemV2Entry = this._itemMap[item.parentId];
      if (parent.storeDisplayChildren) {
        updatedItem.storedDisplayChildren = !item.displayChildren;
      }
    }
    if (updatedItem.displayChildren) {
      itemUtils.propagateDisplayChildrenProp(this._itemMap, item.id);
    }
    this._itemMap = { ...this._itemMap, [item.id]: updatedItem };
    this.itemDisplayChildrenChanged.emit({
      originalItem: item.originalItem,
      item: updatedItem.originalItem,
      currentSelectedState: {
        selected: updatedItem.selected,
        indeterminate: updatedItem.indeterminate,
        displayChildren: updatedItem.displayChildren
      },
      fixedStateMap: this._itemMap,
      fullStateItem: itemUtils.composeItemWithCurrentStateFromMap(this._itemMap, 'root')
    });
  }

  // This method divides label into 3 parts if the query is a substring of the label
  // We need this method to highlight found substring in the label.
  private composeLabelParts(label: string): string[] {
    if (isNullOrUndefinedOrEmptyString(this.query) || (
      this.queryCaseSensitive ?
        label.indexOf(this.query) === -1 :
        label.toLowerCase().indexOf(this.query.toLowerCase()) === -1)
    ) {
      return [];
    }

    const labelParts: string[] = [];
    let labelCursor = 0;
    let itemLabelPartAcc = '';
    while (labelCursor < label.length) {
      const itemLabelPart = label.substring(labelCursor, labelCursor + this.query.length);
      if (this.queryCaseSensitive ?
        itemLabelPart === this.query :
        itemLabelPart.toLowerCase() === this.query.toLowerCase()) {
        if (itemLabelPartAcc.length > 0) {
          labelParts.push(itemLabelPartAcc);
          itemLabelPartAcc = '';
        }
        labelParts.push(itemLabelPart);
        labelCursor += this.query.length;
      } else {
        itemLabelPartAcc += label.substring(labelCursor, labelCursor + 1);
        labelCursor++;
      }
    }
    if (itemLabelPartAcc.length > 0) {
      labelParts.push(itemLabelPartAcc);
    }
    return labelParts;
  }
}
